  origin_unknown: boolean;
  cut_date: string | null;
  received_date: string | null;
  started_date: string | null;
  rooted_date: string | null;
  initial_quantity: number | null;
  viable_quantity: number | null;
  counts_unknown: boolean;
  status: string;
  grow_id: string | null;
  tent_id: string | null;
  notes: string | null;
